            $this->lock('update');

            // Prepare the update query
            $query = $this->db->prepare("UPDATE students SET name = :name, email = :email, course = :course, updated_at = NOW() WHERE id = :id");

            // Bind parameters
            $query->bindParam(':name', $update['name']);
            $query->bindParam(':email', $update['email']);
            $query->bindParam(':course', $update['course']);

            if ($where !== null && isset($where['id'])) {
                $query->bindParam(':id', $where['id']);
            } else {
                throw new InvalidArgumentException("Student ID toh specify karna padega, yaar.");
            }

            // Execute the query
            $success = $query->execute();

            $this->unlock('update');

            if ($success) {
