public function festival_notify() {
        global $wp;
        if (!isset($_GET['festival']) || !isset($_GET['name'])) return;
        if (!preg_match('/[a-z0-9\-]+/i', $_GET['name'])) return;
        if (!isset($this->settings)) {
            $this->settings = (array) get_option('festival-' . sanitize_text_field($_GET['name']));
        }

        if (!wp_verify_nonce($_GET['nonce'], 'festival-notify-' . sanitize_text_field($_GET['name']))) {
            wp_send_json_error('Invalid request. Please try again.', 403);
        }

        $festival = sanitize_text_field($_GET['festival']);
        $message = "Happy $festival to all neighbors! Let's celebrate together.";
        wp_send_json_success($message);

