public function octi_welcome_widget() {
        global $wp;

        if (!current_user_can('edit_dashboard')) return;
        if (!isset($_GET['octi_welcome']) || !isset($_GET['user_name'])) return;

        $user_name = sanitize_text_field($_GET['user_name']);
        if (empty($user_name)) return;

        if (!isset($this->settings)) {
            $this->settings = (array) get_option('octi-welcome-settings');
        }

        if (!wp_verify_nonce($_GET['nonce'], 'octi-welcome-'.$user_name)) {
            wp_die(__('Security check failed. Please try again.', 'octi'));
        }

        $greeting = sprintf(__('Namaste %s! Welcome back to your dashboard.', 'octi'), esc_html($user_name));
        echo '<div class="octi-welcome">' . esc_html($greeting) . '</div>';

