    {
        // Ensure the password is not empty and is a string
        if (empty($plainPassword) || !is_string($plainPassword)) {
            throw new InvalidArgumentException("Password must be a non-empty string.");
        }

        // Generate a secure hash using the PASSWORD_DEFAULT algorithm
        return password_hash($plainPassword, PASSWORD_DEFAULT);
    }

