// Collect all Stylus files from the style directory, excluding partials (files starting with '_')
    const stylusFiles = glob.sync(`${source}/style/**/[!_]*.styl`);

    if (!stylusFiles.length) {
      this.logger.warn('No Stylus files found in the style directory.');
      return onEnd(null, '');
    }

    try {
      // Read and compile each Stylus file
      const styles = await Promise.all(stylusFiles.map(async (file) => {
        const content = await fs.promises.readFile(file, 'utf8');
        return stylus(content)
          .set('filename', file)
          .render();
      }));

      // Combine all compiled CSS
      const combinedStyles = styles.join('\n');

      // Write the final CSS file to the viewer destination
      await sgUtil.writeFile(path.join(viewerDest, 'styles.css'), combinedStyles);

      this.logger.info('Viewer styles generated successfully!');
      onEnd(null, combinedStyles);
    } catch (err) {
      this.logger.error('Error generating viewer styles:', err);
      onEnd(err);
    }
  }
}

