def prepare_festival_data(self, festival_name=None):
        if festival_name is None:
            festival_name = 'Diwali'

        data_path = relative_path(f'estivals/{festival_name.lower()}/data')

        with open(data_path) as data_file:
            festival_data = json.load(data_file)

        return self._process_festival_data(festival_data, festival_name)

    def _process_festival_data(self, data, festival):
        recipes = []
        traditions = []

        for item in data:
            recipes.append(item['special_dish'])
            traditions.append(item['cultural_activity'])

        return {
            'festival': festival,
            'recipes': recipes,
            'traditions': traditions
        }

