def clear(pkg):
    os.chdir(XwalkPath)
    temp_dir = ConstPath + "/../temp_build/" + pkg
    archive_file = ConstPath + "/../downloads/" + pkg + ".zip"

    if os.path.exists(temp_dir):
        try:
            logging.debug("Removing temporary directory: " + temp_dir)
            shutil.rmtree(temp_dir)
        except Exception as e:
            logging.error("Failed to remove temp directory: " + str(e))
            raise

    if os.path.exists(archive_file):
        try:
            logging.debug("Removing archive file: " + archive_file)
            os.remove(archive_file)
        except Exception as e:
            logging.error("Failed to remove archive file: " + str(e))
            raise

    logging.info("Cleanup completed successfully for package: " + pkg)

